<template>
	<view class="w-full relative">
		<view v-if="!load">

			<view class="content">

				<!-- йЎ¶йғЁдҝЎжҒҜ -->
				<view class="w-full flex justify-between">
					<view class="flex">
						<view class="preview">
							еҗҢжӯҘжӢҚ.<text v-if="details.category.status==0">йў„еұ•дёӯ</text><text
								v-else-if="details.category.status==1">жӢҚеҚ–дёӯ</text><text v-else>е·Із»“жӢҚ</text>
						</view>
						<view class="downTime" v-if="details.category.status==0 && downTime1">
							и·қејҖжӢҚ {{downTime1}}
						</view>


					</view>
					<view style="line-height: 30px;" :class=" scribeMessage==1 ? 'activeColor':''"
						@click="sendSubscriptionInformation()">жҸҗйҶ’</view>
				</view>

				<!-- дё“еңәеҗҚз§° -->
				<view class="w-full cate_name">
					{{details.category.cate_name}}
				</view>

				<!-- дё“еңәд»Ӣз»Қ -->
				<view class="w-full mt-20 flex justify-between">
					<view class="w-38">
						<image :src="details.category.big_pic" class="w-full" mode="widthFix"
							@click="previewImage(details.category.big_pic)"></image>
					</view>
					<view class="w-58 lineH-40">
						<view>жӢҚеҚ–ж—¶й—ҙ: {{details.category.startTime1}}</view>
						<view>дҝқиҜҒйҮ‘: {{margin}}</view>
						<view>дҪЈйҮ‘: {{commission}}</view>
						<view>еӣҙи§Ӯ: {{details.category.view}}</view>
						<view>еҮәд»·: {{bid}}</view>
					</view>
				</view>
			</view>




			<view class="mt-15 bg">
				<view class="flex justify-between w-full productBox">
					<view class="flex productTitle">
						<view :class="active==0 ? 'active':'' " @click="changeActive(0)">жӢҚе“Ғ({{details.product.length}})
						</view>
						<view class="ml-20" :class="active==1 ? 'active':'' " @click="getAuctionDetails()">жӢҚеҚ–иҜҰжғ…</view>
					</view>
				</view>
				<scroll-view scroll-y :style="'height:' + scroolH +'px'" class="bg" :scroll-into-view="scrollIntoId"
					v-if="active==0">
					<view v-for="item in details.product" class="w-full flex justify-between mt-25"
						style="padding: 0 10px;" @click="todetails(item.id)" :id="'item-'+item.id">
						<view class="w-30" :style="'height:' + imageH + 'px'">
							<image :src="item.image" class="w-full productImage" mode="aspectFill">
							</image>
						</view>

						<view class="w-66">
							<view class="bold">Lot {{item.index}} {{item.store_name}}</view>
							<view class="mt-8 bg2">
								<image :src="bg2" class="w-full" mode="widthFix"></image>
								<view class="w-full productState">
									<view class="w-full flex justify-between">
										<view class="productStatus">
											<text v-if="details.category.status==0">йў„еұ•дёӯ</text>
											<text
												v-else-if="details.category.status==1 && details.category.number == item.index">жӢҚеҚ–дёӯ</text>
											<text
												v-else-if="details.category.status==1 && details.category.number < item.index">еҚіе°ҶејҖе§Ӣ</text>
											<text v-else>е·Із»“жӢҚ</text>
										</view>
										<view class="w-68"
											v-if="details.category.status== 0 && details.category.startTime > now ">и·қејҖжӢҚ:
											{{downTime1}}
										</view>
									</view>
								</view>
							</view>
							<view class="w-full bold mt-8 fontSize-16">
								<view v-if="item.price==0 && details.category.number <= item.index">иө·жӢҚд»·
									{{item.ot_price}}</view>
								<view
									v-else-if="item.price!=0 && details.category.number <=item.index && details.category.status!=2">
									еҪ“еүҚд»· {{item.price}}</view>
								<view v-else>иҗҪж§Ңд»· {{item.price}}</view>
							</view>

							<view class="w-full bold mt-8" style="font-size: 14px;color: #999999;"
								v-if="(details.category.status==0 && item.count>0) || (details.category.status==1 && details.category.number<=item.index)">
								еҮәд»·ж¬Ўж•° {{item.count}}
							</view>
							<view class="w-full bold mt-8"
								v-if="details.category.status==2 || (details.category.status==1 && details.category.number>item.index)">
								{{item.presale_end_time}} з»“жӢҚ
							</view>
						</view>
					</view>
					<view style="height: 130px;width: 100%;"></view>
				</scroll-view>
				<scroll-view v-else>
					
					<mp-html :content="article.content" />
					<view style="height: 130px;width: 100%;"></view>
				</scroll-view>

			</view>

			<!-- еә•йғЁжҢүй’® -->
			<view class="bottom w-full bg">
				<view class="bg-e w-full lineH-40 center" v-if="plate">
					еҸ·зүҢ{{plate}},еү©дҪҷеҸҜз«һжӢҚйўқеәҰ: <text v-if="remaining<1000000">{{remaining}}</text><text v-else>99999999</text>
				</view>
				<view style="padding: 15px 10px;">
					<view class="w-full plateBtn bg-e" v-if="details.category.status==2">е·Із»“жӢҚ</view>
					<view class="w-full plateBtn" v-else-if="!plate" @click="addNumberPlate()">еҠһзҗҶеҸ·зүҢ</view>
					<view class="w-full plateBtn" v-else-if="state==0" @click="marginShow()">зјҙзәідҝқиҜҒйҮ‘</view>
					<view class="w-full plateBtn" v-else @click="toBidding()">иҝӣе…Ҙдё“еңә</view>
					<!--<view class="w-full flex justify-between" style="padding: 8px 0;">
						<view>еү©дҪҷйўқеәҰ: 0</view>
						<view>еҶ»з»“йўқеәҰ: 0</view>
					</view>-->
				</view>
			</view>

			<u-popup v-model="show" mode="bottom">
				<view style="padding: 100px 10px;">
					<view><u-button type="primary" @click="pay(100000)">дё“еңәеӣәе®ҡдҝқиҜҒйҮ‘(10w)</u-button></view>
					<view style="margin-top: 20px;"><u-button type="success"
							@click="marginRatio()">жҜ”дҫӢдҝқиҜҒйҮ‘(1:5)</u-button></view>
				</view>

			</u-popup>

			<u-popup v-model="popupShow" mode="center">
				<view style="padding: 20px 10px;border-radius: 5px;">
					<view class="setAmountb">
						жҜ”дҫӢдҝқиҜҒйҮ‘(1:5)
					</view>
					<view class="flex" style="margin-top: 20px;">
						<view class="btn" @click="addValue(0)">
							-</view>
						<view class="amountb">
							<input type="number" :value="value" style="height: 50px;" :disabled="true" />
						</view>
						<view class="btn" @click="addValue(1)">
							+</view>
					</view>
					<view class="flex justify-between">
						<view class="flex justify-between w-full" style="margin-top: 20px;">
							<view class="bold p-10-0 center agentbtn1" style="width: 48%;border-radius: 5px;"
								@click="pay(0)">еҸ–ж¶Ҳ</view>
							<view class="bold p-10-0 center ml-10 text-white agentbtn2"
								style="width: 48%;border-radius: 5px;" @click="pay(value)">зјҙзәідҝқиҜҒйҮ‘</view>
						</view>
					</view>
				</view>

			</u-popup>

			<u-popup v-model="popupShows" mode="bottom" border-radius="10">
				<view style="padding: 20px 8px;">
					<view style="text-align: right;">
						<image src="@/static/images/close.png" style="width: 20px;" mode="widthFix" @click="noshoW()">
						</image>
					</view>
					<view style="width: 300px;margin: 0 auto;">
						<image src="https://mtpm.billionwz.com/statics/images/fwh.jpg" class="w-full" mode="widthFix"
							show-menu-by-longpress>
						</image>
					</view>
					<view style="text-align: center;color:  #a71f24;">
						й•ҝжҢүжү«з Ғе…іжіЁжңҚеҠЎеҸ·
					</view>
				</view>
			</u-popup>
		</view>
		<view v-else class="middle">
			<u-loading mode="circle"></u-loading>
		</view>
	</view>
</template>

<script>
	import mpHtml from '@/node_modules/mp-html/dist/uni-app/components/mp-html/mp-html'
	import {
		synchronizationlist,
		auctionDetails,
		getNumberPlate,
		getNumberdetails,
		getwxpay,
		//auctionDetails,
	} from '@/api/store.js';
	import {
		getUserInfo,
		SendSubscribeMessage,
		getScribeMessage
	} from '../../api/user';
	export default {
		components: {
			mpHtml
		},
		data() {
			return {
				id: 0,
				load: true, //жҳҜеҗҰеҠ иҪҪе®ҢжҲҗ
				details: "", //иҜҰжғ…
				bid: 0, //еҮәе®¶ж¬Ўж•°
				timer: null,
				downTime1: "", //еҖ’и®Ўж—¶
				now: 0, //зҺ°еңЁж—¶й—ҙ
				margin: "RMB 100,000жҲ–1:5", //дҝқиҜҒйҮ‘
				commission: "13.5%-15%",
				scroolH: 0,
				plate: "", //еҸ·зүҢ
				state: 0,
				imageH: 0,
				bg2: "https://mtpm.billionwz.com/statics/images/bg2.png",
				userInfo: "",
				uid: 0,
				remaining: 0, //еү©дҪҷйўқеәҰ
				freeze: 0, //еҶ»з»“йўқеәҰ
				show: false,
				//margin: 0,
				popupShow: false,
				value: 10000,
				openId: "",
				popupShows: false,
				scribeMessage: 0,
				scrollIntoId: "",
				active: 0,
				article: ""
			}
		},
		onLoad(options) {
			const system = uni.getSystemInfoSync();
			const wx = uni.getMenuButtonBoundingClientRect();
			this.id = options.id;
			this.imageH = system.windowWidth * 0.3 + 15;
			//console.log(system.windowHeight);
			this.scroolH = system.windowHeight - 80;
			this.getUserInfo();
			this.popupShows = true;
			//this.getScribeMessages()
		},
		onShow() {
			this.getPlateNumberdetails(0);
			this.getsynchronizationlist();
			getApp().globalData.type = {
				type: 'category1',
				data: {
					id: this.id,

				}
			};

			this.sendMessage({
				type: 'category1',
				data: {
					id: this.id,

				}
			});

			this.sendData({
				type: 'category1',
				data: {
					id: this.id,

				}
			})
			this.getScribeMessages()
		},
		onHide() {
			clearInterval(this.time1);
			this.time1 = null;
			getApp().globalData.type = "";
			uni.$off('socketMessage', this.handleMessage);
		},
		onUnload() {
			clearInterval(this.time1);
			this.time1 = null;
			getApp().globalData.type = "";
			uni.$off('socketMessage', this.handleMessage);

		},

		onShareAppMessage() {
			const that = this;
			return {
				title: that.details.category.cate_name, // еҲҶдә«ж Үйўҳ
				path: '/pages/goods_cate/synchronouslist?id=' + this.id, // еҲҶдә«зҡ„йЎөйқўи·Ҝеҫ„пјҢйҖҡеёёжҗәеёҰдёҖдәӣеҸӮж•°
				imageUrl: that.details.category.big_pic // еҸҜйҖүпјҢиҮӘе®ҡд№үеҲҶдә«еӣҫзүҮ
			};
		},


		onShareTimeline() {
			const that = this;
			return {
				title: that.details.category.cate_name, // еҲҶдә«ж Үйўҳ
				path: '/pages/goods_cate/synchronouslist?id=' + this.id, // еҲҶдә«зҡ„йЎөйқўи·Ҝеҫ„пјҢйҖҡеёёжҗәеёҰдёҖдәӣеҸӮж•°
				imageUrl: that.details.category.big_pic // еҸҜйҖүпјҢиҮӘе®ҡд№үеҲҶдә«еӣҫзүҮ
			};
		},

		methods: {
			handleMessage(data) {

				//console.log(data);
				if (data['type'] == 'category1') {
					//console.log(data);
					const data1 = JSON.parse(data.data);
					//const data1 = data.data;
					const that = this;
					that.details = data1;

					if (that.load == true) {
						that.load = false;
					}

					const date = new Date(that.details.category.startTime * 1000);
					//let year = date.getFullYear();
					let month = ('0' + (date.getMonth() + 1)).slice(-2); // жңҲд»Ҫд»Һ0ејҖе§ӢпјҢйңҖиҰҒ+1
					let day = ('0' + date.getDate()).slice(-2);
					let hours = ('0' + date.getHours()).slice(-2);
					let minutes = ('0' + date.getMinutes()).slice(-2);
					//let seconds = ('0' + date.getSeconds()).slice(-2);

					that.details.category.startTime1 = `${month}жңҲ${day}ж—Ҙ ${hours}:${minutes}`;


					var bid1 = 0;
					for (let i = 0; i < that.details.product.length; i++) {
						that.details.product[i].index = i + 1;
						bid1 = bid1 + that.details.product[i].count;
						if (that.details.product[i].presale_end_time > 0) {
							const date = new Date(that.details.product[i].presale_end_time * 1000);
							//let year = date.getFullYear();
							let month = ('0' + (date.getMonth() + 1)).slice(-2); // жңҲд»Ҫд»Һ0ејҖе§ӢпјҢйңҖиҰҒ+1
							let day = ('0' + date.getDate()).slice(-2);
							let hours = ('0' + date.getHours()).slice(-2);
							let minutes = ('0' + date.getMinutes()).slice(-2);


							that.details.product[i].presale_end_time = `${month}жңҲ${day}ж—Ҙ ${hours}:${minutes}`;
						}
					}
					that.bid = bid1;
					var time = Date.now();
					var downtime1 = that.details.category.startTime * 1000 - time;
					if (downtime1 > 0) {
						this.downTime();
					}

				}
			},

			sendMessage(message) {
				uni.$on('socketMessage', this.handleMessage);
				this.time1 = setInterval(() => {
					if (getApp().globalData.socketTask && getApp().globalData.socketTask.readyState === getApp()
						.globalData.socketTask.OPEN) {
						// еҸ‘йҖҒж¶ҲжҒҜпјҢйҖҡеёёе°Ҷж¶ҲжҒҜеҜ№иұЎиҪ¬жҚўдёәJSONеӯ—з¬ҰдёІ
						getApp().globalData.socketTask.send({
							data: JSON.stringify(message),
							success: () => {
								console.log("еҸ‘йҖҒжҲҗеҠҹ");
							},
							fail: (err) => {
								console.error('ж¶ҲжҒҜеҸ‘йҖҒеӨұиҙҘ', err);
							}
						});
					} else {
						console.warn('WebSocket иҝһжҺҘжңӘе»әз«ӢпјҢж— жі•еҸ‘йҖҒж¶ҲжҒҜ');
					}
				}, 20000)
			},


			sendData(message) {
				if (getApp().globalData.socketTask && getApp().globalData.socketTask.readyState === getApp().globalData
					.socketTask.OPEN) {
					// еҸ‘йҖҒж¶ҲжҒҜпјҢйҖҡеёёе°Ҷж¶ҲжҒҜеҜ№иұЎиҪ¬жҚўдёәJSONеӯ—з¬ҰдёІ
					getApp().globalData.socketTask.send({
						data: JSON.stringify(message),
						success: () => {
							console.log("еҸ‘йҖҒжҲҗеҠҹ");
						},
						fail: (err) => {
							console.error('ж¶ҲжҒҜеҸ‘йҖҒеӨұиҙҘ', err);
						}
					});
				} else {
					console.warn('WebSocket иҝһжҺҘжңӘе»әз«ӢпјҢж— жі•еҸ‘йҖҒж¶ҲжҒҜ');
				}
			},

			/*
			 * иҺ·еҸ–з”ЁжҲ·дҝЎжҒҜ
			 */
			getUserInfo: function() {
				let that = this;
				getUserInfo().then((res) => {

					that.userInfo = res.data;
					that.uid = res.data.uid;
					//console.log(res.data);
				});
			},

			/**
			 * иҺ·еҸ–дё“еңәдҝЎжҒҜ
			 */
			getsynchronizationlist() {
				const that = this;
				synchronizationlist(that.id).then((res) => {
					//	console.log(res);
					that.details = res.data;
					if (that.load == true) {
						that.load = false;
					}

					const date = new Date(that.details.category.startTime * 1000);
					//let year = date.getFullYear();
					let month = ('0' + (date.getMonth() + 1)).slice(-2); // жңҲд»Ҫд»Һ0ејҖе§ӢпјҢйңҖиҰҒ+1
					let day = ('0' + date.getDate()).slice(-2);
					let hours = ('0' + date.getHours()).slice(-2);
					let minutes = ('0' + date.getMinutes()).slice(-2);
					//let seconds = ('0' + date.getSeconds()).slice(-2);

					that.details.category.startTime1 = `${month}жңҲ${day}ж—Ҙ ${hours}:${minutes}`;


					var bid1 = 0;
					for (let i = 0; i < that.details.product.length; i++) {
						that.details.product[i].index = i + 1;
						if (that.details.product[i].index == that.details.category.number) {
							that.scrollIntoId = "item-" + that.details.product[i].id;
						}
						bid1 = bid1 + that.details.product[i].count;
						if (that.details.product[i].presale_end_time > 0) {
							const date = new Date(that.details.product[i].presale_end_time * 1000);
							//let year = date.getFullYear();
							let month = ('0' + (date.getMonth() + 1)).slice(-2); // жңҲд»Ҫд»Һ0ејҖе§ӢпјҢйңҖиҰҒ+1
							let day = ('0' + date.getDate()).slice(-2);
							let hours = ('0' + date.getHours()).slice(-2);
							let minutes = ('0' + date.getMinutes()).slice(-2);


							that.details.product[i].presale_end_time = `${month}жңҲ${day}ж—Ҙ ${hours}:${minutes}`;
						}
					}
					that.bid = bid1;
					var time = Date.now();
					var downtime1 = that.details.category.startTime * 1000 - time;
					if (downtime1 > 0) {
						this.downTime();
					}

				})
			},

			/**
			 * еҖ’и®Ўж—¶
			 */
			downTime() {
				const that = this;
				this.timer = setInterval(() => {
					var time = Date.now();
					var downtime = that.details.category.startTime * 1000 - time;
					that.now = time / 1000;
					if (downtime <= 0) {
						that.getsynchronizationlist();
						that.downTime1 = `0еӨ©0ж—¶0еҲҶ0з§’` // жӣҝжҚўж•ҙдёӘж•°з»„	
						clearInterval(that.timer)
						that.timer = null; // йҮҚиҰҒпјҡжё…йҷӨеҗҺйҮҚзҪ®еј•з”Ё

					} else if (downtime > 0) {
						const d = Math.floor(downtime / 86400000);
						const h = Math.floor((downtime % 86400000) / 3600000);
						const m = Math.floor((downtime % 3600000) / 60000);
						const s = Math.floor((downtime % 60000) / 1000);
						that.downTime1 = `${d}еӨ©${h}ж—¶${m}еҲҶ${s}з§’` // жӣҝжҚўж•ҙдёӘж•°з»„		
					}



				}, 1000)
			},

			//еҠһзҗҶеҸ·зүҢ
			addNumberPlate() {
				const that = this;
				//console.log(this.userInfo);
				if (!this.userInfo) {
					this.getUserInfo();
					return;
				}

				if (!this.userInfo.card_id) {
					uni.showModal({
						title: "жҸҗзӨә",
						content: 'иҜ·е…Ҳе®ҢжҲҗе®һеҗҚи®ӨиҜҒ',
						confirmText: "еҺ»з»‘е®ҡ",
						success: function(res) {
							if (res.confirm) {
								uni.navigateTo({
									url: "/pages/realName/index"
								})
							} else if (res.cancel) {

							}
						}
					})
					return;
				}
				getNumberPlate(that.id).then((res) => {
					//console.log(res);
					that.getPlateNumberdetails(1);
				})
			},

			//иҺ·еҸ–еҸ·зүҢ
			getPlateNumberdetails(index) {
				const that = this;
				//console.log(that.details.category);
				getNumberdetails(that.id).then((res) => {
					that.plate = res.data.number_plate;
					that.state = res.data.state;
					that.remaining = res.data.remaining;
					that.freeze = res.data.freeze;
					//that.orderId = res.data.orderId;
					that.openId = res.data.openid.openid;
					//console.log(res.data);
					if (that.plate && index == 1) {
