				})
			},

			//йҖүжӢ©зјҙзәідҝқиҜҒйҮ‘ж–№ејҸ
			marginShow() {
				this.show = true;
			},

			previewImage(url) {
				uni.previewImage({
					current: url, // еҪ“еүҚжҳҫзӨәеӣҫзүҮзҡ„й“ҫжҺҘ
					urls: [url] // йңҖиҰҒйў„и§Ҳзҡ„еӣҫзүҮеҲ—иЎЁпјҲж”ҜжҢҒеӨҡеј пјү
				});
			},

			todetails(idx) {
