			pay(total_fee) {
				this.show = false;
				if (total_fee == 0) {
					this.popupShow = false;
				} else {
					const that = this;
					uni.showModal({
						title: "жҸҗзӨә",
						content: "жҳҜеҗҰж”Ҝд»ҳ" + total_fee + "е…ғдҝқиҜҒйҮ‘пјҢиҺ·еҫ—" + total_fee * 5 + "зҡ„з«һжӢҚйўқеәҰ",
						success(res) {
							if (res.confirm) {
								getwxpay(that.openId, that.id, total_fee).then((res) => {
									that.wxpay(res.data);
								})
							}
						}
					})
				}

			},

			wxpay(paymentParams) {
				const that = this;
				uni.requestPayment({
					// йҖҡз”ЁеҸӮж•°пјҢдёҚеҗҢе№іеҸ°дјҡиҮӘеҠЁиҜҶеҲ«жүҖйңҖеӯ—ж®ө
					provider: 'wxpay', // еӣәе®ҡдёәеҫ®дҝЎж”Ҝд»ҳ
					// еҫ®дҝЎе°ҸзЁӢеәҸжүҖйңҖеҸӮж•°
					timeStamp: paymentParams.timeStamp,
					nonceStr: paymentParams.nonceStr,
					package: paymentParams.package,
					signType: paymentParams.signType,
					paySign: paymentParams.paySign,
					// еҫ®дҝЎAPPж”Ҝд»ҳжүҖйңҖеҸӮж•°пјҲжіЁж„Ҹеӯ—ж®өеҗҚеҸҜиғҪдёҺе°ҸзЁӢеәҸдёҚеҗҢпјҢеҗҺз«Ҝиҝ”еӣһйңҖдҝқжҢҒдёҖиҮҙпјү
					// orderInfo: paymentParams, // жңүж—¶APPж”Ҝд»ҳдјҡе°ҶжүҖжңүеҸӮж•°ж”ҫеңЁorderInfoеҜ№иұЎдёӯ
					// е…·дҪ“еҸӮиҖғ UniApp е®ҳж–№ж–ҮжЎЈ: https://uniapp.dcloud.io/api/plugins/payment

					success: (res) => {
						//console.log('ж”Ҝд»ҳжҲҗеҠҹ', res);
						//that.getPlateNumberdetails();
						uni.showToast({
							title: 'ж”Ҝд»ҳжҲҗеҠҹ'
						});
						setTimeout(() => {
							// иҝҷйҮҢж”ҫзҪ®йңҖиҰҒе»¶ж—¶жү§иЎҢзҡ„д»Јз Ғ
							that.getPlateNumberdetails(0);
						}, 2000);

						that.popupShow = false;
						// ж”Ҝд»ҳжҲҗеҠҹеҗҺзҡ„дёҡеҠЎйҖ»иҫ‘пјҢдҫӢеҰӮи·іиҪ¬еҲ°жҲҗеҠҹйЎөйқў
					},
					fail: (err) => {
						//console.log('ж”Ҝд»ҳеӨұиҙҘ', err);
						// з”ЁжҲ·еҸ–ж¶Ҳж”Ҝд»ҳжҲ–ж”Ҝд»ҳеӨұиҙҘеӨ„зҗҶ
						let errMsg = 'ж”Ҝд»ҳеӨұиҙҘ';
						if (err.errMsg === 'requestPayment:fail cancel') {
							errMsg = 'жӮЁе·ІеҸ–ж¶Ҳж”Ҝд»ҳ';
						}
						uni.showToast({
							title: errMsg,
							icon: 'none'
						});
					}
				});
			},


