				uni.requestSubscribeMessage({
					tmplIds: [tmplId], // ж•°з»„ж јејҸпјҢдёҖж¬ЎжңҖеӨҡ3жқЎ[citation:2]
					success: (res) => {
						// res ж јејҸзӨәдҫӢпјҡ{ errMsg: "requestSubscribeMessage:ok", 'жЁЎжқҝID': 'accept' }
						if (res[tmplId] === 'accept') {

							SendSubscribeMessage(tmplId, that.id).then((res) => {
								//console.log('з”ЁжҲ·еҗҢж„Ҹи®ўйҳ…');
								uni.showToast({
									title: 'з”ЁжҲ·еҗҢж„Ҹи®ўйҳ…'
								});

								that.getScribeMessages();
							})


							// йҖҡеёёжӯӨеӨ„е°ҶжҺҲжқғжҲҗеҠҹж ҮиҜҶпјҲеҰӮз”ЁжҲ·зҡ„codeпјүеҸ‘йҖҒз»ҷиҮӘе·ұзҡ„еҗҺз«ҜжңҚеҠЎеҷЁ
						} else if (res[tmplId] === 'reject') {

							uni.showToast({
								title: 'з”ЁжҲ·жӢ’з»қи®ўйҳ…'
							});
						} else if (res[tmplId] === 'ban') {
							uni.showToast({
								title: 'е·Іиў«еҗҺеҸ°е°Ғ'
							});
							//console.log('е·Іиў«еҗҺеҸ°е°ҒзҰҒ');
						}
					},
					fail: (err) => {
						console.error('и°ғз”ЁжҺҲжқғжҺҘеҸЈеӨұиҙҘ:', err);
						// еӨ„зҗҶеӨұиҙҘжғ…еҶөпјҢдҫӢеҰӮз”ЁжҲ·еҪ»еә•е…ій—ӯдәҶйҖҡзҹҘжқғйҷҗ (err.errCode === 20004)[citation:7]
					}
				});
			},

			getScribeMessages() {
				getScribeMessage(this.id).then((res) => {
					if (res.msg == "true") {
						this.scribeMessage = 1;
					}
				})
			},

			getAuctionDetails() {
				const that = this;

				if (that.article) {
					that.active = 1;
					return;
				}
				console.log(that.details.category.article_id);
				auctionDetails(that.details.category.article_id).then((res) => {
					that.article = res.data;
					console.log(res.data)
					that.active = 1;
				})
			},
			
			
			changeActive(index) {
				this.active = index;
			},
		}
	}
